<script setup lang="ts">
import { computed } from 'vue';
import { useRouter } from 'vue-router';
import { HelpCircle, ChevronRight } from 'lucide-vue-next';
import { useAdminStore } from '@/store/useAdminStore';
import dayjs from 'dayjs';

const TODAY = computed(() => dayjs().format('YYYY-MM-DD'));
const adminStore = useAdminStore();
const router = useRouter();

const stats = computed(() => {
  const todayRecords = adminStore.records.filter((r) => r.date === TODAY.value);
  return {
    signedIn: todayRecords.filter((r) => r.status === 'signedIn').length,
    absent: todayRecords.filter((r) => r.status === 'absent').length,
    unsigned: todayRecords.filter((r) => r.status === 'unsigned').length,
  };
});
</script>

<template>
  <div class="w-full rounded-card border border-black/5 bg-white/40 px-5 py-4 shadow-[0_4px_16px_-8px_rgba(0,0,0,0.08)] backdrop-blur-md dark:border-white/10 dark:bg-white/10">
    <!-- 标题行：今日统计 + 查看详情 -->
    <div class="flex items-center justify-between">
      <div class="flex items-center gap-1">
        <span class="text-[14px] font-medium text-ink">今日统计</span>
        <HelpCircle :size="13" class="text-muted" />
      </div>
      <button
        type="button"
        class="flex items-center gap-0.5 text-[12px] font-medium text-primary active:scale-95"
        @click="router.push('/records')"
      >
        查看详情
        <ChevronRight :size="13" :stroke-width="2.5" />
      </button>
    </div>

    <!-- 数据行 -->
    <div class="mt-3.5 flex items-center gap-2.5">
      <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-primary-light py-2.5">
        <span class="text-[18px] font-bold text-primary leading-none">
          {{ stats.signedIn }}
        </span>
        <span class="text-[11px] text-primary">正常</span>
      </div>
      <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-warning-light py-2.5">
        <span class="text-[18px] font-bold text-warning leading-none">
          {{ stats.absent }}
        </span>
        <span class="text-[11px] text-warning">缺勤</span>
      </div>
      <div class="flex flex-1 items-center justify-center gap-1 rounded-lg bg-black/5 py-2.5 dark:bg-white/5">
        <span class="text-[18px] font-bold text-ink leading-none">
          {{ stats.unsigned }}
        </span>
        <span class="text-[11px] text-muted">未点名</span>
      </div>
    </div>
  </div>
</template>
