<script setup lang="ts">
import { computed, ref } from 'vue';
import { Check, ChevronLeft, ChevronRight, Undo2, Loader2 } from 'lucide-vue-next';
import { useRollCallStore } from '@/store/useRollCallStore';
import { useSound } from '@/composables/useSound';

const store = useRollCallStore();
const sound = useSound();

const list = computed(() => store.filteredList);
const merchant = computed(() => list.value[store.currentIndex]);

// 堆叠卡片：当前 + 后2张（探探式堆叠）
const stack = computed(() => list.value.slice(store.currentIndex, store.currentIndex + 3));

const statusLabel = computed(() => {
  const m = merchant.value;
  if (!m) return '';
  if (m.signedIn) return '已到岗';
  if (m.absent) return '缺勤';
  return '未签到';
});

// ===== 状态机 =====
type Phase = 'idle' | 'dragging' | 'submitting' | 'animating';
const phase = ref<Phase>('idle');

const offsetX = ref(0);
const transitionOn = ref(true); // 拖动时关闭以跟手
const ripple = ref(false);
const cardKey = ref(0); // 重建 key，清空 transition 残留
const promoting = ref(false); // 主卡飞出时，第二张卡片同步上移放大

// 拖动临时变量
let startX = 0;
let startY = 0;
let lockMode = 0; // 0=未开始, 1=横向, 2=垂直锁定
let decided = false;
let pointerId: number | null = null;
let cardWidth = 300;
let justDragged = false;

const MAX_ROTATE = 18; // 探探幅度
const locked = computed(() => phase.value !== 'idle');

function isProcessed() {
  const m = merchant.value;
  return !m || m.signedIn || m.absent;
}
function threshold() {
  return Math.max(50, cardWidth * 0.35); // 探探手感阈值
}

// ===== 主卡滑动 =====
function onPointerDown(e: PointerEvent) {
  if (locked.value || isProcessed()) return;
  if (e.pointerType === 'mouse' && e.button !== 0) return;
  cardWidth = (e.currentTarget as HTMLElement).offsetWidth || 300;
  startX = e.clientX;
  startY = e.clientY;
  pointerId = e.pointerId;
  lockMode = 0;
  decided = false;
  transitionOn.value = false;
  sound.unlock();
}

function onPointerMove(e: PointerEvent) {
  if (phase.value !== 'idle' && phase.value !== 'dragging') return;
  if (lockMode === 2) return;
  if (pointerId !== e.pointerId) return;
  const dx = e.clientX - startX;
  const dy = e.clientY - startY;

  if (!decided) {
    if (Math.abs(dx) < 8 && Math.abs(dy) < 8) return;
    decided = true;
    if (Math.abs(dy) > Math.abs(dx)) {
      lockMode = 2;
      return;
    }
    lockMode = 1;
    phase.value = 'dragging';
    try {
      (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
    } catch { /* ignore */ }
  }

  if (lockMode !== 1) return;
  // 阻尼：超出 80% 卡片宽度后衰减
  const maxOffset = cardWidth * 0.85;
  let target = dx;
  if (Math.abs(dx) > maxOffset) {
    const excess = Math.abs(dx) - maxOffset;
    target = Math.sign(dx) * (maxOffset + excess * 0.25);
  }
  offsetX.value = target;
}

function onPointerUp(e: PointerEvent) {
  if (phase.value !== 'dragging') {
    if (lockMode !== 0) { offsetX.value = 0; }
    lockMode = 0; pointerId = null;
    return;
  }
  if (pointerId !== e.pointerId) return;
  try {
    (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId);
  } catch { /* ignore */ }

  const off = offsetX.value;
  const th = threshold();
  lockMode = 0;
  pointerId = null;
  transitionOn.value = true;
  justDragged = true;
  setTimeout(() => { justDragged = false; }, 60);

  if (off <= -th) {
    submit('absent', -1);
  } else if (off >= th) {
    if (store.canUndo) {
      doUndo();
    } else {
      sound.play('bounce');
      offsetX.value = 0;
      phase.value = 'idle';
    }
  } else {
    sound.play('bounce');
    offsetX.value = 0;
    phase.value = 'idle';
  }
}

function onPointerCancel(_e?: PointerEvent) {
  if (lockMode === 1) {
    transitionOn.value = true;
    offsetX.value = 0;
  }
  lockMode = 0;
  pointerId = null;
  if (phase.value === 'dragging') phase.value = 'idle';
}

// ===== 点击圆环到岗 =====
function onCircleClick() {
  if (locked.value || isProcessed() || justDragged) return;
  submit('signedIn', 1);
}

// ===== 统一提交：API → 成功飞出（+第二张上移）/ 失败回弹 =====
async function submit(action: 'signedIn' | 'absent', dir: 1 | -1) {
  const m = merchant.value;
  if (!m) return;
  phase.value = 'submitting';
  transitionOn.value = true;
  sound.play(action === 'signedIn' ? 'signedIn' : 'absent');
  if (action === 'signedIn') {
    ripple.value = true;
    setTimeout(() => { ripple.value = false; }, 500);
  }
  try {
    await store.checkin(m.id, action);
    // 成功 → 主卡飞出 + 第二张同步上移放大
    promoting.value = true;
    offsetX.value = dir * (window.innerWidth + 120);
    phase.value = 'animating';
    setTimeout(() => {
      transitionOn.value = false;
      offsetX.value = 0;
      promoting.value = false;
      if (!store.isAllDone) store.nextMerchant();
      cardKey.value++;
      requestAnimationFrame(() => {
        transitionOn.value = true;
        phase.value = 'idle';
      });
    }, 300);
  } catch {
    offsetX.value = 0;
    phase.value = 'idle';
    showError(action === 'signedIn' ? '到岗提交失败，请重试' : '缺勤提交失败，请重试');
  }
}

// ===== 右滑撤销 =====
async function doUndo() {
  if (!store.canUndo) {
    sound.play('bounce');
    offsetX.value = 0;
    phase.value = 'idle';
    return;
  }
  phase.value = 'submitting';
  transitionOn.value = true;
  sound.play('undo');
  offsetX.value = 0;
  try {
    await store.undoLast();
    cardKey.value++;
    requestAnimationFrame(() => {
      phase.value = 'idle';
    });
  } catch {
    phase.value = 'idle';
    showError('撤销失败，请重试');
  }
}

async function undoFromEmpty() {
  if (phase.value !== 'idle' || !store.canUndo) return;
  phase.value = 'submitting';
  sound.play('undo');
  try {
    await store.undoLast();
    cardKey.value++;
  } catch {
    showError('撤销失败，请重试');
  }
  phase.value = 'idle';
}

// ===== 错误提示 =====
const errorMsg = ref('');
let errorTimer: ReturnType<typeof setTimeout> | undefined;
function showError(msg: string) {
  errorMsg.value = msg;
  if (errorTimer) clearTimeout(errorTimer);
  errorTimer = setTimeout(() => { errorMsg.value = ''; }, 2500);
}

// ===== 主卡样式：跟手 translateX + rotate（±18°）=====
const cardStyle = computed(() => {
  const ratio = cardWidth > 0 ? offsetX.value / cardWidth : 0;
  const rotate = Math.max(-MAX_ROTATE, Math.min(MAX_ROTATE, ratio * MAX_ROTATE * 1.6));
  return {
    transform: `translateX(${offsetX.value}px) rotate(${rotate}deg)`,
    transition: transitionOn.value ? 'transform 0.32s cubic-bezier(0.22, 0.61, 0.36, 1)' : 'none',
    willChange: 'transform',
    touchAction: 'pan-y',
    zIndex: 30,
  };
});

// ===== 堆叠层样式：第二、三张缩放下移，主卡飞出时第二张上移放大 =====
function stackStyle(i: number) {
  if (i === 0) return cardStyle.value;
  // i=1,2 下方卡片
  const isNext = i === 1;
  const baseScale = isNext ? 0.93 : 0.86;
  const baseY = isNext ? 14 : 28;
  const baseOpacity = isNext ? 0.85 : 0.55;
  // 主卡飞出时，第二张上移放大成新主卡
  const scale = isNext && promoting.value ? 1 : baseScale;
  const ty = isNext && promoting.value ? 0 : baseY;
  const opacity = isNext && promoting.value ? 1 : baseOpacity;
  return {
    transform: `translateY(${ty}px) scale(${scale})`,
    transition: 'transform 0.32s cubic-bezier(0.22, 0.61, 0.36, 1), opacity 0.32s ease',
    willChange: 'transform',
    zIndex: 30 - i * 10,
    opacity,
    pointerEvents: 'none' as const,
  };
}

// ===== 大标签（探探式 NOPE/LIKE 圆角边框）=====
const badge = computed(() => {
  const off = offsetX.value;
  const th = threshold();
  const ratio = th > 0 ? Math.min(Math.abs(off) / th, 1) : 0;
  if (off < -2) {
    return { show: true, side: 'left' as const, text: '缺勤', color: '#EF4444', opacity: ratio, rotate: -18 };
  }
  if (off > 2) {
    return { show: true, side: 'right' as const, text: store.canUndo ? '撤销' : '暂无', color: '#6B7280', opacity: ratio, rotate: 18 };
  }
  return { show: false, side: 'left' as const, text: '', color: 'transparent', opacity: 0, rotate: 0 };
});

const showEmpty = computed(() => store.isAllDone && phase.value !== 'animating');
</script>

<template>
  <!-- 空楼层 -->
  <div
    v-if="list.length === 0"
    class="w-full rounded-card border border-black/5 bg-white/40 p-8 text-center text-muted backdrop-blur-md dark:border-white/10 dark:bg-white/10"
  >
    当前楼层暂无商户
  </div>

  <!-- 打卡完成空状态 -->
  <div
    v-else-if="showEmpty"
    v-motion
    :initial="{ opacity: 0, scale: 0.92 }"
    :enter="{ opacity: 1, scale: 1, transition: { duration: 300, ease: 'easeOut' } }"
    class="w-full rounded-card border border-black/5 bg-white/40 px-6 py-10 text-center backdrop-blur-md dark:border-white/10 dark:bg-white/10"
  >
    <div class="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-primary/15">
      <Check :size="34" :stroke-width="3" class="text-primary" />
    </div>
    <div class="mt-3 text-[17px] font-bold text-ink">打卡完成</div>
    <div class="mt-1 text-[12px] text-muted">
      已处理 {{ store.processedCount }}/{{ store.totalCount }} 户
    </div>
    <button
      v-if="store.canUndo"
      type="button"
      :disabled="locked"
      class="mt-4 inline-flex items-center gap-1 rounded-full border border-black/10 bg-white/50 px-4 py-1.5 text-[12px] font-medium text-ink transition-transform active:scale-95 disabled:opacity-50 dark:border-white/15 dark:bg-white/10"
      @click="undoFromEmpty"
    >
      <Undo2 :size="13" :stroke-width="2.5" />
      撤销上一户
    </button>
  </div>

  <!-- 堆叠卡片（探探式）-->
  <div v-else-if="merchant" class="w-full">
    <div class="relative" style="height: 340px">
      <!-- 从底到顶渲染堆叠层 -->
      <div
        v-for="(m, i) in stack"
        :key="m.id + '-' + cardKey"
        class="absolute inset-0 overflow-hidden rounded-card border border-black/5 bg-white/40 px-4 pb-3 pt-3 shadow-[0_6px_20px_-8px_rgba(0,0,0,0.1)] backdrop-blur-md dark:border-white/10 dark:bg-white/10"
        :style="stackStyle(i)"
        @pointerdown="i === 0 ? onPointerDown($event) : undefined"
        @pointermove="i === 0 ? onPointerMove($event) : undefined"
        @pointerup="i === 0 ? onPointerUp($event) : undefined"
        @pointercancel="i === 0 ? onPointerCancel($event) : undefined"
      >
        <!-- 大标签（仅主卡）-->
        <div
          v-if="i === 0 && badge.show"
          class="pointer-events-none absolute z-20 select-none border-[2.5px] px-3 py-1 text-[26px] font-black tracking-wider"
          :class="badge.side === 'left' ? 'left-4 top-5' : 'right-4 top-5'"
          :style="{
            opacity: badge.opacity,
            color: badge.color,
            borderColor: badge.color,
            borderRadius: '10px',
            transform: `rotate(${badge.rotate}deg)`,
          }"
        >
          {{ badge.text }}
        </div>

        <!-- 卡片内容 -->
        <div class="relative z-0 flex h-full flex-col items-center">
          <!-- 楼层标签 + 商户名 -->
          <div class="flex flex-col items-center gap-1" style="margin-bottom: 12px">
            <span class="rounded-md bg-primary-light px-2 py-0.5 text-[10px] font-medium text-primary">
              {{ m.floor }}
            </span>
            <div class="flex items-center gap-1.5">
              <span class="text-[18px] font-bold leading-none text-ink">{{ m.name }}</span>
              <span v-if="m.verified" class="flex h-[15px] w-[15px] items-center justify-center rounded-full bg-primary text-white">
                <Check :size="9" :stroke-width="3.5" />
              </span>
            </div>
          </div>

          <!-- 中心圆环按钮（仅主卡可点）-->
          <div class="relative flex flex-col items-center">
            <div class="dashed-ring absolute inset-0 -m-2 rounded-full" />
            <div
              class="checkin-gradient relative flex cursor-pointer select-none flex-col items-center justify-center rounded-full text-white transition-transform duration-150 hover:scale-110 active:scale-90 active:shadow-inner"
              :class="{ 'pointer-events-none': locked || i !== 0, 'opacity-50': locked }"
              style="width: 120px; height: 120px"
              @click="i === 0 ? onCircleClick() : undefined"
            >
              <Check :size="34" :stroke-width="3.5" class="drop-shadow" />
              <div class="mt-0.5 text-[11px] font-semibold">
                {{ i === 0 ? statusLabel : '点击到岗' }}
              </div>
            </div>
            <span v-if="i === 0 && ripple" class="ripple-wave" />
          </div>

          <!-- 操作提示（仅主卡）-->
          <div v-if="i === 0" class="mt-3 flex items-center justify-between text-[10px] text-muted" style="width: 100%">
            <span class="flex items-center gap-0.5">
              <ChevronLeft :size="11" :stroke-width="2.5" /> 左滑缺勤
            </span>
            <span class="flex items-center gap-0.5" :class="{ 'opacity-40': !store.canUndo }">
              <Undo2 :size="10" :stroke-width="2.5" /> 右滑撤销 <ChevronRight :size="11" :stroke-width="2.5" />
            </span>
          </div>

          <!-- 分页指示（仅主卡）-->
          <div v-if="i === 0" class="mt-1.5 text-center text-[10px] text-muted">
            {{ store.currentIndex + 1 }}/{{ list.length }}
          </div>
        </div>

        <!-- loading 遮罩（仅主卡）-->
        <div
          v-if="i === 0 && phase === 'submitting'"
          class="absolute inset-0 z-30 flex items-center justify-center rounded-card bg-white/45 backdrop-blur-[2px] dark:bg-black/30"
        >
          <Loader2 :size="28" class="animate-spin text-primary" />
        </div>
      </div>
    </div>

    <!-- 错误提示 -->
    <transition name="fade">
      <div v-if="errorMsg" class="mt-2 rounded-card bg-red-500/90 px-3 py-2 text-center text-[12px] font-medium text-white shadow">
        {{ errorMsg }}
      </div>
    </transition>
  </div>
</template>

<style scoped>
.ripple-wave {
  position: absolute;
  top: 50%; left: 50%;
  width: 120px; height: 120px;
  margin: -60px 0 0 -60px;
  border-radius: 50%;
  border: 2px solid var(--theme-color);
  pointer-events: none;
  animation: ripple-out 0.5s ease-out forwards;
}
@keyframes ripple-out {
  0% { transform: scale(0.6); opacity: 0.7; }
  100% { transform: scale(1.8); opacity: 0; }
}
.fade-enter-active, .fade-leave-active { transition: opacity 0.2s ease; }
.fade-enter-from, .fade-leave-to { opacity: 0; }
</style>
