import { ref } from 'vue';

// ===== 全局静音开关（localStorage 持久化）=====
const MUTE_KEY = 'rollcall-sound-muted';
const mutedRef = ref(typeof localStorage !== 'undefined' && localStorage.getItem(MUTE_KEY) === '1');

// ===== AudioContext 单例（懒初始化，避免自动播放策略阻塞）=====
let ctx: AudioContext | null = null;
function getCtx(): AudioContext | null {
  if (typeof window === 'undefined') return null;
  if (!ctx) {
    const AC = window.AudioContext || (window as unknown as { webkitAudioContext?: typeof AudioContext }).webkitAudioContext;
    if (!AC) return null;
    try {
      ctx = new AC();
    } catch {
      return null;
    }
  }
  // 浏览器自动播放策略：首次在用户手势内调用 resume
  if (ctx.state === 'suspended') {
    ctx.resume().catch(() => undefined);
  }
  return ctx;
}

interface ToneOptions {
  freq: number; // 起始频率
  freqEnd?: number; // 结束频率（用于音高滑动）
  duration: number; // 时长 ms
  type: OscillatorType; // 波形
  gain?: number; // 音量 0~1
  delay?: number; // 延迟启动 ms
}

function playTone(opts: ToneOptions) {
  if (mutedRef.value) return;
  const ac = getCtx();
  if (!ac) return;
  const now = ac.currentTime + (opts.delay ?? 0) / 1000;
  const dur = opts.duration / 1000;
  const osc = ac.createOscillator();
  const gain = ac.createGain();
  osc.type = opts.type;
  osc.frequency.setValueAtTime(opts.freq, now);
  if (opts.freqEnd !== undefined && opts.freqEnd !== opts.freq) {
    osc.frequency.exponentialRampToValueAtTime(Math.max(1, opts.freqEnd), now + dur);
  }
  const peak = opts.gain ?? 0.18;
  // 包络：快速起音 + 指数衰减，避免咔哒爆音
  gain.gain.setValueAtTime(0.0001, now);
  gain.gain.exponentialRampToValueAtTime(peak, now + 0.01);
  gain.gain.exponentialRampToValueAtTime(0.0001, now + dur);
  osc.connect(gain).connect(ac.destination);
  osc.start(now);
  osc.stop(now + dur + 0.02);
}

export type SoundType = 'absent' | 'signedIn' | 'undo' | 'bounce';

export function useSound() {
  const muted = mutedRef;

  function setMuted(v: boolean) {
    mutedRef.value = v;
    try {
      localStorage.setItem(MUTE_KEY, v ? '1' : '0');
    } catch {
      /* ignore */
    }
    // 切换静音时也尝试解锁 AudioContext
    if (!v) getCtx();
  }

  function toggleMuted() {
    setMuted(!mutedRef.value);
  }

  function play(type: SoundType) {
    switch (type) {
      case 'absent':
        // 低沉短促：220Hz → 110Hz 下滑，方波带厚度
        playTone({ freq: 220, freqEnd: 110, duration: 160, type: 'sine', gain: 0.22 });
        playTone({ freq: 110, freqEnd: 70, duration: 200, type: 'triangle', gain: 0.12, delay: 30 });
        break;
      case 'signedIn':
        // 清脆成功：880Hz → 1320Hz 上行双音
        playTone({ freq: 880, duration: 90, type: 'triangle', gain: 0.2 });
        playTone({ freq: 1320, duration: 180, type: 'sine', gain: 0.18, delay: 80 });
        break;
      case 'undo':
        // 中性切换：440Hz 短音，方波略冷
        playTone({ freq: 440, freqEnd: 380, duration: 110, type: 'square', gain: 0.1 });
        break;
      case 'bounce':
        // 轻轻微响：极短 600Hz 软音
        playTone({ freq: 600, duration: 50, type: 'sine', gain: 0.08 });
        break;
    }
  }

  // 在首次用户手势内调用一次以解锁 AudioContext
  function unlock() {
    getCtx();
  }

  return { muted, setMuted, toggleMuted, play, unlock };
}
