<script setup lang="ts">
import { computed } from 'vue';
import { Volume2, VolumeX } from 'lucide-vue-next';
import TopBar from '@/components/home/TopBar.vue';
import ProgressCard from '@/components/home/ProgressCard.vue';
import FloorTabs from '@/components/home/FloorTabs.vue';
import CheckinCard from '@/components/home/CheckinCard.vue';
import StatsBar from '@/components/home/StatsBar.vue';
import { useRollCallStore } from '@/store/useRollCallStore';
import { useSound } from '@/composables/useSound';

const store = useRollCallStore();
const sound = useSound();

const processed = computed(() => store.processedCount);
const total = computed(() => store.totalCount);
const percent = computed(() => (total.value > 0 ? Math.round((processed.value / total.value) * 100) : 0));
</script>

<template>
  <div class="flex h-full flex-col overflow-y-auto no-scrollbar">
    <div class="mx-auto flex w-full max-w-[430px] flex-col gap-2 px-gutter pb-24">
      <!-- 顶部标题天气区 -->
      <TopBar />
      <!-- 今日点名进度卡片 -->
      <div v-motion :initial="{ opacity: 0, y: 16 }" :enter="{ opacity: 1, y: 0, transition: { duration: 250, ease: 'easeOut', delay: 120 } }">
        <ProgressCard />
      </div>
      <!-- 楼层筛选标签栏 -->
      <div v-motion :initial="{ opacity: 0, y: 16 }" :enter="{ opacity: 1, y: 0, transition: { duration: 250, ease: 'easeOut' } }">
        <FloorTabs />
      </div>

      <!-- 打卡进度条 + 音效开关 -->
      <div
        v-motion
        :initial="{ opacity: 0, y: 16 }"
        :enter="{ opacity: 1, y: 0, transition: { duration: 250, ease: 'easeOut', delay: 150 } }"
        class="flex items-center gap-2"
      >
        <div class="flex-1">
          <div class="mb-1 flex items-center justify-between text-[10px] text-muted">
            <span>打卡进度</span>
            <span>{{ processed }}/{{ total }}</span>
          </div>
          <div class="h-1.5 overflow-hidden rounded-full bg-black/10 dark:bg-white/10">
            <div
              class="h-full rounded-full bg-primary transition-all duration-300"
              :style="{ width: percent + '%' }"
            />
          </div>
        </div>
        <button
          type="button"
          class="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-white/40 text-muted backdrop-blur-md transition-transform active:scale-90 dark:bg-white/10"
          :class="{ 'opacity-50': sound.muted.value }"
          :aria-label="sound.muted.value ? '开启音效' : '关闭音效'"
          @click="sound.toggleMuted()"
        >
          <VolumeX v-if="sound.muted.value" :size="14" />
          <Volume2 v-else :size="14" />
        </button>
      </div>

      <!-- 商户签到卡片 -->
      <div v-motion :initial="{ opacity: 0, y: 16 }" :enter="{ opacity: 1, y: 0, transition: { duration: 250, ease: 'easeOut', delay: 180 } }">
        <CheckinCard />
      </div>

      <!-- 历史状态弱提示 -->
      <div
        v-if="!store.canUndo && total > 0"
        class="text-center text-[10px] text-muted/50"
      >
        暂无记录，无法回退
      </div>

      <!-- 今日统计底部栏 -->
      <div v-motion :initial="{ opacity: 0, y: 16 }" :enter="{ opacity: 1, y: 0, transition: { duration: 250, ease: 'easeOut', delay: 60 } }">
        <StatsBar />
      </div>
    </div>
  </div>
</template>
