<script setup lang="ts">
import { computed, ref, onMounted } from 'vue';
import { Sun, Moon } from 'lucide-vue-next';
import { useAdminStore } from '@/store/useAdminStore';
import { useWeather } from '@/composables/useWeather';
import { applyThemeMode, applyThemeColor, getStoredTheme, toggleThemeMode, type ThemeMode } from '@/lib/utils';
import dayjs from 'dayjs';

const WEEKDAY = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];

const adminStore = useAdminStore();
const mallName = computed(() => adminStore.systemConfig.mallName || '名创广场');
const now = dayjs();
const dateText = `${now.year()}年${now.month() + 1}月${now.date()}日 ${WEEKDAY[now.day()]}`;
const timeText = now.format('HH:mm');

// 和风天气 - 阿克苏市
const { weather } = useWeather();

// 亮/暗模式
const themeMode = ref<ThemeMode>('light');
onMounted(() => {
  themeMode.value = getStoredTheme();
});
function handleToggleTheme() {
  themeMode.value = toggleThemeMode();
  // 切换主题后重新应用主题色，使 light 变体在亮/暗下生成不同明度
  applyThemeColor(adminStore.systemConfig?.themeColor || '#00b578');
}
// 兜底：若其他地方修改了 html class，保持 ref 同步
function syncFromDom() {
  themeMode.value = document.documentElement.classList.contains('dark') ? 'dark' : 'light';
}
applyThemeMode(getStoredTheme());
syncFromDom();
</script>

<template>
  <div class="flex w-full items-start justify-between pt-4 pb-1">
    <div class="flex min-w-0 flex-col gap-1.5">
      <div class="text-[15px] font-semibold leading-tight text-ink">
        {{ dateText }}
      </div>
      <!-- 商场名 | 时间 | 天气图标 温度 | 天气状况（同一行） -->
      <div class="flex flex-wrap items-center gap-2 text-[12px] text-muted">
        <span>{{ mallName }}</span>
        <span class="text-white/30">丨</span>
        <span>{{ timeText }}</span>
        <template v-if="weather">
          <span class="text-white/30">丨</span>
          <i :class="`qi-${weather.icon}`" class="text-[14px] leading-none text-[#f59e0b]"></i>
          <span>{{ weather.temp }}°C</span>
          <span class="text-white/30">丨</span>
          <span>{{ weather.text }}</span>
        </template>
      </div>
    </div>

    <!-- 亮/暗切换按钮 -->
    <button
      type="button"
      class="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-card text-ink shadow-sm active:scale-95"
      :aria-label="themeMode === 'dark' ? '切换到亮色模式' : '切换到暗色模式'"
      @click="handleToggleTheme"
    >
      <Sun v-if="themeMode === 'dark'" :size="16" :stroke-width="2.5" />
      <Moon v-else :size="16" :stroke-width="2.5" />
    </button>
  </div>
</template>
