<script setup lang="ts">
import { computed } from 'vue';
import { useAdminStore } from '@/store/useAdminStore';
import dayjs from 'dayjs';

const TODAY = computed(() => dayjs().format('YYYY-MM-DD'));
const adminStore = useAdminStore();

const stats = computed(() => {
  const todayRecords = adminStore.records.filter((r) => r.date === TODAY.value);
  const signedIn = todayRecords.filter((r) => r.status === 'signedIn').length;
  const absent = todayRecords.filter((r) => r.status === 'absent').length;
  const named = signedIn + absent;
  const rate = adminStore.merchants.length > 0 ? Math.round((named / adminStore.merchants.length) * 100) : 0;
  return { named, total: adminStore.merchants.length, rate };
});

const circumference = 2 * Math.PI * 30;
const ringOffset = computed(() => circumference * (1 - stats.value.rate / 100));
</script>

<template>
  <div class="w-full rounded-card border border-black/5 bg-white/40 px-4 py-2 shadow-[0_4px_16px_-8px_rgba(0,0,0,0.08)] backdrop-blur-md dark:border-white/10 dark:bg-white/10">
    <!-- 标题 -->
    <div class="mb-1 flex items-center gap-1.5">
      <span class="h-3.5 w-1 rounded-full bg-primary" />
      <span class="text-[13px] font-medium text-ink">今日点名进度</span>
    </div>

    <!-- 数字 + 环形圈 -->
    <div class="flex items-center justify-between">
      <!-- 左：大数字 + 已点名 -->
      <div class="flex flex-col">
        <div class="flex items-baseline gap-1">
          <span class="text-[26px] font-bold text-ink leading-none">
            {{ stats.named }}
          </span>
          <span class="text-[13px] text-muted">/ {{ stats.total }} 户</span>
        </div>
        <div class="mt-1.5 flex items-center gap-1">
          <span class="text-[11px] font-medium text-primary">
            {{ stats.rate }}% 已点名
          </span>
        </div>
      </div>

      <!-- 右：环形进度圈 -->
      <div class="relative shrink-0">
        <svg width="76" height="76" viewBox="0 0 76 76" class="ring-progress">
          <circle cx="38" cy="38" r="30" fill="none" stroke="var(--progress-track)" stroke-width="6" />
          <circle
            cx="38"
            cy="38"
            r="30"
            fill="none"
            stroke="var(--theme-color)"
            stroke-width="6"
            stroke-linecap="round"
            :stroke-dasharray="circumference"
            :stroke-dashoffset="ringOffset"
          />
        </svg>
        <div class="absolute inset-0 flex flex-col items-center justify-center">
          <span class="text-[15px] font-bold text-primary leading-none">
            {{ stats.rate }}%
          </span>
          <span class="mt-0.5 text-[9px] text-muted leading-none">点名率</span>
        </div>
      </div>
    </div>
  </div>
</template>
